"use strict";(globalThis.webpackChunkai_roadmap_docs=globalThis.webpackChunkai_roadmap_docs||[]).push([[1746],{7998(e){e.exports=JSON.parse('{"tag":{"label":"software-architecture","permalink":"/documentation/docs/tags/software-architecture","allTagsPath":"/documentation/docs/tags","count":36,"items":[{"id":"software-architecture/data-consistency","title":"Arquitectura de Datos y Consistencia","description":"Data & Scale","permalink":"/documentation/docs/software-architecture/data-consistency"},{"id":"software-architecture/data-structures/linear/array","title":"Array","description":"An `array` stores contiguous elements in memory, allowing access by index in constant time.","permalink":"/documentation/docs/software-architecture/data-structures/linear/array"},{"id":"software-architecture/data-structures/linear/array-list","title":"Array List","description":"An `ArrayList` (also known as a Dynamic Array) is a data structure that uses an internal Array to store elements, but has the ability to automatically resize itself.","permalink":"/documentation/docs/software-architecture/data-structures/linear/array-list"},{"id":"software-architecture/data-structures/non-linear/AVL-tree","title":"AVL Tree","description":"An AVL tree is a self-balancing binary search tree where the height difference between the left and right subtrees of each node is at most 1. Invented in 1962 by Adelson-Velskii and Landis, it guarantees O(log n) operations.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/AVL-tree"},{"id":"software-architecture/data-structures/non-linear/b-trees","title":"B trees","description":"A B-Tree is a self-balancing tree data structure designed for efficient disk-based storage and retrieval, where each node can have multiple children (not just 2 like binary trees). It\'s widely used in databases (MySQL, PostgreSQL) and filesystems (NTFS, ext4) because it minimizes disk I/O by keeping data highly local.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/b-trees"},{"id":"software-architecture/data-structures/non-linear/binary-tree","title":"Binary Tree","description":"Python does not have native binary trees, but they are implemented with a Node class that contains data and left/right pointers. Each node can have up to 2 children, which is useful for efficient searches (O(log n)).","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/binary-tree"},{"id":"software-architecture/data-structures/index","title":"Data Structures","description":"Este m\xf3dulo organiza estructuras de datos en dos bloques principales:","permalink":"/documentation/docs/software-architecture/data-structures/"},{"id":"software-architecture/delivery-governance","title":"Delivery, Gobernanza y Evoluci\xf3n","description":"Security & Operations","permalink":"/documentation/docs/software-architecture/delivery-governance"},{"id":"software-architecture/data-structures/linear/deque","title":"Deque","description":"A Deque, short for Double-Ended Queue, is a linear data structure that allows you to insert and delete elements from both the front and the rear.","permalink":"/documentation/docs/software-architecture/data-structures/linear/deque"},{"id":"software-architecture/api-integration","title":"Dise\xf1o de APIs e Integraci\xf3n","description":"Modeling & Boundaries","permalink":"/documentation/docs/software-architecture/api-integration"},{"id":"software-architecture/domain-driven-design","title":"Domain-Driven Design (DDD)","description":"Modeling & Boundaries","permalink":"/documentation/docs/software-architecture/domain-driven-design"},{"id":"software-architecture/scalability-reliability","title":"Escalabilidad y Confiabilidad","description":"Data & Scale","permalink":"/documentation/docs/software-architecture/scalability-reliability"},{"id":"software-architecture/paradigms-and-fundamental-principles/functional-programming","title":"Functional Programming","description":"Paradigms and fundamental principles","permalink":"/documentation/docs/software-architecture/paradigms-and-fundamental-principles/functional-programming"},{"id":"software-architecture/data-structures/non-linear/graph-adjacency-list","title":"Graph adjacency list","description":"Interactive visual - Graph adjacency list","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/graph-adjacency-list"},{"id":"software-architecture/data-structures/non-linear/graph-adjacency-matrix","title":"Graph adjacency matrix","description":"Interactive visual - Graph adjacency matrix","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/graph-adjacency-matrix"},{"id":"software-architecture/data-structures/non-linear/graph-bellman-ford","title":"Graph Bellman-Ford","description":"Bellman-Ford algorithm computes shortest paths from a source node to all others in weighted graphs, handling negative edge weights unlike Dijkstra. It detects negative cycles where shortest paths are undefined. Runs in O(VE) time.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/graph-bellman-ford"},{"id":"software-architecture/data-structures/non-linear/graph-dijkstra","title":"Graph dijkstra","description":"Uses a priority queue to always expand the closest unvisited node. Greedily selects the node with smallest known distance, then \\"relaxes\\" its edges (updates neighbors if shorter path found).","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/graph-dijkstra"},{"id":"software-architecture/data-structures/non-linear/graph-kruskal","title":"Graph Kruskal","description":"Kruskal\'s algorithm finds the Minimum Spanning Tree (MST) of a connected, undirected, weighted graph by greedily selecting edges from lowest to highest weight without forming cycles. Created by Joseph Kruskal in 1956, runs in O(E log E) time using Union-Find.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/graph-kruskal"},{"id":"software-architecture/data-structures/non-linear/graph-prim","title":"Graph Prim","description":"Prim\'s algorithm builds the Minimum Spanning Tree (MST) by growing a single tree from a starting vertex, always adding the cheapest edge connecting a tree vertex to a non-tree vertex. Vertex-centric approach, O(E log V) with priority queue.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/graph-prim"},{"id":"software-architecture/data-structures/non-linear/graph-traversal-bfs-dfs","title":"Graph Traversal bfs dfs","description":"Interactive visual - Graph traversal bfs dfs","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/graph-traversal-bfs-dfs"},{"id":"software-architecture/data-structures/non-linear/heaps","title":"Heaps","description":"A heap is a complete binary tree data structure that satisfies the heap property: parent nodes are either greater than (max-heap) or smaller than (min-heap) their children. Stored in arrays for cache efficiency, it\'s the backbone of priority queues with O(log n) insert/extract operations.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/heaps"},{"id":"software-architecture/paradigms-and-fundamental-principles/hybrid-paradigms","title":"Hibryd Paradigms","description":"Paradigms and fundamental principles","permalink":"/documentation/docs/software-architecture/paradigms-and-fundamental-principles/hybrid-paradigms"},{"id":"software-architecture/data-structures/linear/linked-list","title":"LinkedList","description":"If the Array was a fixed row of boxes and the ArrayList was an elastic row, the LinkedList is something completely different: imagine a treasure hunt. Each clue gives you an object and a piece of paper that tells you where to find the next clue.","permalink":"/documentation/docs/software-architecture/data-structures/linear/linked-list"},{"id":"software-architecture/paradigms-and-fundamental-principles/object-oriented-programming-oop","title":"Object Oriented Programming OOP","description":"Paradigms and fundamental principles","permalink":"/documentation/docs/software-architecture/paradigms-and-fundamental-principles/object-oriented-programming-oop"},{"id":"software-architecture/programming","title":"Paradigms and fundamental principles","description":"Foundations","permalink":"/documentation/docs/software-architecture/programming"},{"id":"software-architecture/architectural-patterns","title":"Patrones Arquitect\xf3nicos","description":"Foundations","permalink":"/documentation/docs/software-architecture/architectural-patterns"},{"id":"software-architecture/system-design-principles","title":"Principios de System Design","description":"Foundations","permalink":"/documentation/docs/software-architecture/system-design-principles"},{"id":"software-architecture/data-structures/linear/queue","title":"Queue","description":"A queue is a linear data structure that follows the FIFO (First-In, First-Out) principle, which means that the first item to enter is the first to leave.","permalink":"/documentation/docs/software-architecture/data-structures/linear/queue"},{"id":"software-architecture/paradigms-and-fundamental-principles/reactive-programming","title":"Reactive Programming","description":"Paradigms and fundamental principles","permalink":"/documentation/docs/software-architecture/paradigms-and-fundamental-principles/reactive-programming"},{"id":"software-architecture/data-structures/non-linear/red-black-trees","title":"Red black tree","description":"A Red-Black Tree is a self-balancing binary search tree where each node has a color (red or black) to maintain balance through specific rules. It guarantees O(log n) operations while allowing fewer rotations than AVL trees, making it widely used in standard libraries like C++\'s std::map and Java\'s TreeMap.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/red-black-trees"},{"id":"software-architecture/references","title":"Referencias de Software Architecture","description":"Libros clave","permalink":"/documentation/docs/software-architecture/references"},{"id":"software-architecture/security-resilience","title":"Seguridad Arquitect\xf3nica y Resilience","description":"Security & Operations","permalink":"/documentation/docs/software-architecture/security-resilience"},{"id":"software-architecture/index","title":"Software Architecture \u2014 Roadmap Completo","description":"Software Architecture","permalink":"/documentation/docs/software-architecture"},{"id":"software-architecture/data-structures/linear/stack","title":"Stack","description":"A stack is a linear data structure that follows the LIFO (Last-In, First-Out) principle, which means that the last element to enter is the first to leave.","permalink":"/documentation/docs/software-architecture/data-structures/linear/stack"},{"id":"software-architecture/data-structures/non-linear/binary-search-tree","title":"Tree - Binary Search Tree","description":"A Binary Search Tree is a node-based binary tree data structure which has the following properties:","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/binary-search-tree"},{"id":"software-architecture/data-structures/non-linear/tries","title":"Tries","description":"A Trie (prefix tree) is a tree-like data structure that stores a dynamic set of strings efficiently, optimized for prefix-based operations like autocomplete, spell-checking, and IP routing. Each node represents one character, and paths from root to leaf spell complete words.","permalink":"/documentation/docs/software-architecture/data-structures/non-linear/tries"}],"unlisted":false}}')}}]);